#include<bits/stdc++.h>
using namespace std;
int q;
long long dp[1001], n, f[1001], ans;
string c;
int main() {
	cin >> q >> c;
	n = c.size();
	for (int i = 0; i < n; i++) {
		int p = c[i] - '0';
		p %= q;
		for (int j = 0; j < q; j++) {
			f[j] = dp[j], dp[j] = 0;
		}
		for (int j = 0; j < q; j++) {
			dp[(j * 10 + p) % q] += f[j];
		}
		dp[p]++;
		ans += dp[0];
	}
	cout << ans;
}
